entry.content:
三马车之javaScript，控制页面的行为

输出简单输出
// 内容写入弹出窗口alert(&#x27;HelloWorld!&#x27;);// 内容写入hml文档document.write(&#x27;HelloWorld!&#x27;);// 内容写入浏览器控制台console.log(&#x27;HelloWorld!&#x27;)

通过id选择性输出
// 选取id=demo的元素并innerHTML来获取或插入元素内容document.getElementById(&quot;demo&quot;).innerHTML = &quot;段落已修改&quot;;//  获取id=demo元素的值document.getElementById(&quot;demo&quot;).value;

通过button行为调用函数输出
//通过按钮来执行输出函数(显示时间)&lt;button onclick=&quot;myFunction()&quot;&gt;点我&lt;/button&gt;&lt;script&gt;    function myFunction()&#123;        document.write(Date());    &#125;&lt;/script&gt;
注释
类似于c的注释

单行注释
// 这是一行注释
多行注释
/*这是多行注释1这是多行注释2*/
行末使用注释
var Ez=666;//声明Ez并赋值666

字面量一般固定值被称为字面量
数字字面量  小数 整数 科学计数(e)
3.14 ;1001 ;123e5 ;
字符字面量 可使用单引号或双引号
&quot;Frank Cassidy&quot;&#x27;Frank Cassidy&#x27;
表达式字面量 用于计算
5 + 6;5 * 10;
数组字面量定义数组
[40, 100, 1, 5, 25, 10]
对象字面量定义对象，里面类似于c++的成员
&#123;firstName:&quot;John&quot;, lastName:&quot;Doe&quot;, age:50,eyeColor:&quot;black&quot;&#125;
函数字面量可以返回为值或直接空
function myFunciton(a,b)&#123;    return ;&#125;
变量通常用关键字var定义变量，使用=给变量赋值
var x, length;x = 5;lenght = 6;
一条语句多个变量//一行声明var lastname=&quot;Doe&quot;, age=30, job=&quot;carpenter&quot;;//跨行声明var lastname=&quot;Doe&quot;,age=30,job=&quot;carpenter&quot;;

禁止🚫多个变量同时赋同一个值
var x,y,z=1;
x,y为undefined，z为1
操作符算术运算符&amp;赋值运算符+ - * / =
数据类型字面量的类型：数据类型。有六种

String(字符串)
Number(数值) 
Boolean(布尔值)
Null (空值)
Undefined(未定义)
Object(对象)


基本数据类型：String(字符串)、Number(数值)、Boolean(布尔值)、 Null (空值)、Undefined(未定义)引用数据类型：Object(对象)

一般的变量命名后未赋值，此时为Undefiend未定义
document.write(16+&quot;Volve&quot;)// 输出16Volve

字母大小写&amp;字符集
js对字母大小写严格区分js使用Unicode字符集

函数 getElementById 与 getElementbyID 是不同的。同样，变量 myVariable 与 MyVariable 也是不同的。
代码&amp;代码块形式浏览器按照代码编写顺序依次执行每条语句向网页输出两个段落
document.getElementById(&quot;demo&quot;).innerHTML = &quot;Hello Dolly&quot;;document.getElementById(&quot;myDiv&quot;).innerHTML = &quot;最近如何？&quot;;
代码块以左花括号开始，以右花括号结束。一并地执行语句序列
function myFunction()&#123;    ocument.getElementById(&quot;demo&quot;).innerHTML = &quot;Hello Dolly&quot;;    document.getElementById(&quot;myDiv&quot;).innerHTML = &quot;最近如何？&quot;;    return ;&#125;
标识符
js中自主命名的都是标识符
例如变量名、函数名、属性名
命名规则  1.含有字母、数字、_、$  2.不能数字开头  3.不能是关键字和保留字  4.驼峰命名法
首字母小写，每个单词开头大写，其余小写  例如：helloWorld


以下列出关键字  点击以打开  

	语句
	描述


break
用于跳出循环。


catch
语句块，在 try 语句块执行出错时执行 catch 语句块。


continue
跳过循环中的一个迭代。


do ... while
执行一个语句块，在条件语句为 true 时继续执行该语句块。


for
在条件语句为 true 时，可以将代码块执行指定的次数。 


for ... in 
用于遍历数组或者对象的属性（对数组或者对象的属性进行循环操作）。


function
定义一个函数


if ... else
用于基于不同的条件来执行不同的动作。


return
退出函数


switch
用于基于不同的条件来执行不同的动作。


throw
抛出（生成）错误 。 


try
实现错误处理，与 catch 一同使用。 


var
声明一个变量。


while
当条件语句为 true 时，执行语句块。 





多行写一句&amp;一行写多句使用反斜杠对代码进行换行
document.write(&quot;Hello\!World&quot;);
用;隔开
document.write(&quot;HelloWorld!&quot;);doucment.write(&quot;Ty&quot;);
选择与循环Ifif (condition1)&#123;    当条件1为true时执行代码&#125;else if(condition2) &#123;    当条件2为true时执行代码&#125;else &#123;    当条件1和条件2都不为true时执行代码&#125;
switchswitch(n)&#123;    case 1:        执行代码块1        break;    case 2:        执行代码块2        break;    default:        与case 1和case 2 不同时执行的代码&#125;
Forfor(语句1;语句2;语句3)&#123;    被执行的代码块&#125;
For&#x2F;In循环遍历对象的属性
代码预览var x;//x为person的属性名var txt=&quot;&quot;;var person=&#123;fname:&quot;Bill&quot;,lname:&quot;Gates&quot;,age:56&#125;; for (x in person)&#123;	txt=txt + person[x];&#125;document.write(txt);

	var x;
	var txt="";
	var person={fname:"Bill",lname:"Gates",age:56}; 
	for (x in person){
		txt=txt + person[x];
	}
	document.getElementById("demo").innerHTML=txt;


while&amp;do&#x2F;while循环与c语言的类似
while (condition)&#123;    code1;&#125;do&#123;    code1;&#125;while(condition);
Break用于跳出循环，继续执行循环后的的代码
代码预览var i=0,x=&quot;&quot;;for(i=0;i&lt;10;i++)&#123;    if(i==3)&#123;        break;    &#125;    x=x+&quot;The number is &quot;+ i +&quot; &lt;br&gt;&quot;;&#125;    document.write(x);
var i=0,x="";
for(i=0;i

对象是变量(键值对)的容器

定义对象var person =&#123;    // key:value    firstName: &quot;Frank&quot;,    lastName:&quot;Liang&quot;,    age:21,    eyeColor:&quot;black&quot;&#125;;
对象属性即对象中的键值对
firstName: &quot;Frank&quot;,lastName: &quot;Liang&quot;,age: 21,eyeColor: &quot;black&quot;

访问对象属性两种方法
person.firstName;person[&quot;firstName&quot;];

对象方法对象内定义的函数
var person =&#123;    // key:value    firstName: &quot;Frank&quot;,    lastName:&quot;Liang&quot;,    age:21,    eyeColor:&quot;black&quot;    // 对象方法    fullName: function()&#123;        return this.firstName+&quot; &quot;+this.lastName;    &#125;&#125;;
访问对象方法Object.methodName();
代码预览var person =&#123;    // key:value    firstName: &quot;Frank&quot;,    lastName:&quot;Liang&quot;,    age:21,    eyeColor:&quot;black&quot;,    // 对象方法    fullName: function()&#123;        return this.firstName+&quot; &quot;+this.lastName;    &#125;&#125;;var P1=person.fullName();document.write(P1);
var person ={
    // key:value
    firstName: "Frank",
    lastName:"Liang",
    age:21,
    eyeColor:"black",
    // 对象方法
    fullName: function(){
        return this.firstName+" "+this.lastName;
    }
};
var P1=person.fullName();
document.write(P1);


不加()则会返回函数的定义

代码预览var person =&#123;    // key:value    firstName: &quot;Frank&quot;,    lastName:&quot;Liang&quot;,    age:21,    eyeColor:&quot;black&quot;,    // 对象方法    fullName: function()&#123;        return this.firstName+&quot; &quot;+this.lastName;    &#125;&#125;;var P1=person.fullName;document.write(P1);
var person ={
    // key:value
    firstName: "Frank",
    lastName:"Liang",
    age:21,
    eyeColor:"black",
    // 对象方法
    fullName: function(){
        return this.firstName+" "+this.lastName;
    }
};
var P1=person.fullName;
document.write(P1);

转字符串全局方法String()

这里的值可以是任何类型

String(值);
方法toString()
值.toString();

数字
这里值只能是数字

String(数字);值.toString();
布尔值
true同理

string(false);false.toString();

日期
函数Date()自动返回字符串

Date();String(Date());obj=new Date();obj.toString();
转数字全局方法Number()可以将字符串转化为数字，其他字符转成NaN(非数字)
布尔值Number(false);//return 0Number(true);//return 1
日期getTime()直接获取数字形式时间获取的是从 1970 年 1 月 1 日午夜到指定日期之间的毫秒数

所以每次刷新获取的值都不同

代码预览d=new Date();document.write(Number(d)+&quot;&lt;br&gt; &quot;);document.write(d.getTime());
d=new Date();
document.write(Number(d)+" ");
document.write(d.getTime());


自动转换类型
当js尝试操作一个“错误”的数据类型时，会自动转换为“正确”的数据类型


数字+null
字符串+null
字符串+数字
字符串-数字

5 + null    // 返回 5         null 转换为 0&quot;5&quot; + null  // 返回&quot;5null&quot;   null 转换为 &quot;null&quot;&quot;5&quot; + 1     // 返回 &quot;51&quot;      1 转换为 &quot;1&quot; &quot;5&quot; - 1     // 返回 4         &quot;5&quot; 转换为 5
转换为字符串当尝试输出对象或变量时js会自动调用变量的toString()方法
myVar = &#123;name:&quot;Fjohn&quot;&#125;  // toString 转换为 &quot;[object Object]&quot;myVar = [1,2,3,4]       // toString 转换为 &quot;1,2,3,4&quot;myVar = new Date()      // toString 转换为 &quot;Fri Jul 18 2014 09:08:55 GMT+0200&quot;
数字和布尔值也经常相互转换：
myVar = 123             // toString 转换为 &quot;123&quot;myVar = true            // toString 转换为 &quot;true&quot;myVar = false           // toString 转换为 &quot;false&quot;

模板语法Vue使用基于html的模板语法，允许将DOM绑定到底层Vue实例的数据
文本插值双大括号语法文本插值 (Mustache)

插数据

&lt;span&gt;message:&#123;&#123;msg&#125;&#125;&lt;/span&gt;&lt;!-- 绑定v-once，一次性插值，不会再变化 --&gt;&lt;span v-once&gt;这个将不会改变：&#123;&#123;msg&#125;&#125;&#125;&lt;/span&gt;

插HTML代码原始HTML 双括号会解释为普通文本而不是HTML代码，输出真正的HTML需要v-html指令

&lt;p&gt;Using mustaches:&#123;&#123;rawHtml&#125;&#125;&lt;/p&gt;&lt;p&gt;Using v-html idrective:&lt;span v-html=&quot;rawHtml&quot;&gt;&lt;/span&gt;&lt;/p&gt;

HTML属性(Attribute)绑定  Attribute mustache语法不能作用在HTML attribute上，这时候要用v-bind指令动态绑定id  &lt;div v-bind:id=&quot;dynamicId&quot;&gt; &lt;/div&gt;&lt;!-- dynamicId`为变量) --&gt;&lt;button v-bind:disabled=&quot;isButtonDisabled&quot;&gt;Button&lt;/button&gt;

js表达式支持使用javaScript表达式 对于所有数据的绑定vue.js都提供了完全的js表达式支持&#123;&#123;number+1&#125;&#125;&lt;br&gt;&#123;&#123;ok?&#x27;Yes&#x27;:&#x27;No&#x27;&#125;&#125;&lt;br&gt;&#123;&#123;message.split(&#x27;&#x27;).reverse().join(&#x27;&#x27;)&#125;&#125;&lt;div v-bind:id=&quot;&#x27;list-&#x27;+dynamicId&quot;&gt;&lt;/div&gt;

但不支持js语句和条件控制 （也就是包含关键字的语句），如var、if、return等

说白了所谓计算方法就是添加一个方法如下例子，想要展示已出版书籍
export default &#123;  data() &#123;    return &#123;      author: &#123;        name: &#x27;John Doe&#x27;,        books: [          &#x27;Vue 2 - Advanced Guide&#x27;,          &#x27;Vue 3 - Basic Guide&#x27;,          &#x27;Vue 4 - The Mystery&#x27;        ]      &#125;    &#125;  &#125;
&lt;p&gt;Has published books:&lt;/p&gt;&lt;span&gt;&#123;&#123; author.books.length &gt; 0 ? &#x27;Yes&#x27; : &#x27;No&#x27; &#125;&#125;&lt;/span&gt;
但是因为耦合较高不好维护，所以将HTML内的表达式改成方法改进如下
export default &#123;  data() &#123;    return &#123;      author: &#123;        name: &#x27;John Doe&#x27;,        books: [          &#x27;Vue 2 - Advanced Guide&#x27;,          &#x27;Vue 3 - Basic Guide&#x27;,          &#x27;Vue 4 - The Mystery&#x27;        ]      &#125;    &#125;  &#125;,  computed: &#123;    // 一个计算属性的 getter    publishedBooksMessage() &#123;      // `this` 指向当前组件实例      return this.author.books.length &gt; 0 ? &#x27;Yes&#x27; : &#x27;No&#x27;    &#125;  &#125;&#125;
&lt;p&gt;Has published books:&lt;/p&gt;&lt;span&gt;&#123;&#123; publishedBooksMessage &#125;&#125;&lt;/span&gt;
HTML显示内容为定义的计算方法名称publishedBooksMessage,方便后期维护

绑定HTML class绑定对象可以给:class(v-bind:简写)传递一个对象来动态切换class 
&lt;div :class=&quot;&#123; active: isActive &#125;&quot;&gt;&lt;/div&gt;
表示active 是否存在取决于数据属性isActive的真假值
对象中可以存在多个字段来操作多个class，且可以和普通class共存
data()&#123;    return &#123;        isActive:true,        hasError:false    &#125;&#125;
&lt;div  class=&quot;static&quot;,   :class=&quot;&#123; active: isActive, &#x27;text-danger&#x27;: hasError &#125;&quot;&gt;&lt;/div&gt;
渲染结果为
&lt;div class=&quot;static active&quot;&gt;&lt;/div&gt;

绑定对象不一定要是内联字面量，也可以直接绑定一个对象
data() &#123;  return &#123;    classObject: &#123;      active: true,      &#x27;text-danger&#x27;: false    &#125;  &#125;&#125;
&lt;div :class=&quot;classObject&quot;&gt;&lt;/div&gt;
当然此对象可以是计算方法
data() &#123;  return &#123;    isActive: true,    error: null  &#125;&#125;,computed: &#123;  classObject() &#123;    return &#123;      active: this.isActive &amp;&amp; !this.error,      &#x27;text-danger&#x27;: this.error &amp;&amp; this.error.type === &#x27;fatal&#x27;    &#125;  &#125;&#125;
&lt;div :class=&quot;classObject&quot;&gt;&lt;/div&gt;
